document.querySelectorAll(".nav-link").forEach((o=>{o.addEventListener("click",(function(o){o.preventDefault(),document.querySelector(this.getAttribute("href")).scrollIntoView({behavior:"smooth"})}))}));let scrollTop=document.querySelector(".scroll-top");function toggleScrollTop(){scrollTop&&(window.scrollY>100?scrollTop.classList.add("active"):scrollTop.classList.remove("active"))}scrollTop.addEventListener("click",(o=>{o.preventDefault(),window.scrollTo({top:0,behavior:"smooth"})})),window.addEventListener("load",toggleScrollTop),document.addEventListener("scroll",toggleScrollTop);